// ============================================
// Supports: Credit Card, Bank Transfer, PayPal, Apple Pay, BNPL
// Uses Zod v4 discriminated unions for type-safe payment method handling

// ============================================
// Shared Types & Constants
// ============================================

export const CurrencyEnum = z.enum(['USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD']);
