export type Locale = keyof typeof errorMessages;

// Helper function to get localized error message
export function getErrorMessage(key: keyof typeof errorMessages.en, locale: Locale = 'en'): string {
  return errorMessages[locale][key];
}

// ============================================
// Shared Schemas
// ============================================

const AddressSchema = z.object({
  street: z.string().min(1, { error: 'Street address is required' }),
  city: z.string().min(1, { error: 'City is required' }),
  state: z.string().optional(),
  zipCode: z.string().min(1, { error: 'ZIP/Postal code is required' }),
  country: z.string().min(2, { error: 'Country is required' })
});

const BasePaymentFieldsSchema = z.object({
  orderId: z.string().uuid({ error: 'Invalid order ID format' }),
  amount: z.number().positive({ error: 'Amount must be greater than zero' }),
  currency: CurrencyEnum,
  description: z.string().optional(),
  metadata: z.record(z.string(), z.unknown()).optional()
});

// ============================================
// Payment Method Schemas (Discriminated Union Members)
// ============================================

// Credit Card Payment Schema
const CreditCardPaymentSchema = z.object({
  paymentMethod: z.literal('credit_card'),
  cardNumber: z.string()
    .length(16, { error: 'Please enter a valid 16-digit card number' })
    .regex(/^\d+$/, { error: 'Card number must contain only digits' }),
  cardExpiry: z.string()
    .regex(/^(0[1-9]|1[0-2])\/([0-9]{2})$/, { error: 'Please enter a valid expiry date (MM/YY)' }),
  cardCvv: z.string()
    .length(3, { error: 'Please enter a valid 3-digit CVV' })
    .regex(/^\d+$/, { error: 'CVV must contain only digits' }),
  cardholderName: z.string().min(1, { error: 'Cardholder name is required' }),
  billingAddress: AddressSchema
});

// Bank Transfer Payment Schema
const BankTransferPaymentSchema = z.object({
  paymentMethod: z.literal('bank_transfer'),
  accountNumber: z.string()
    .min(8, { error: 'Account number must be at least 8 digits' })
    .max(17, { error: 'Account number must not exceed 17 digits' })
    .regex(/^\d+$/, { error: 'Account number must contain only digits' }),
  routingNumber: z.string()
    .length(9, { error: 'Routing number must be exactly 9 digits' })
    .regex(/^\d+$/, { error: 'Routing number must contain only digits' }),
  accountName: z.string().min(1, { error: 'Account holder name is required' }),
  bankName: z.string().min(1, { error: 'Bank name is required' }),
  accountType: z.enum(['checking', 'savings']),
  isVerified: z.boolean().optional().default(false),
  billingAddress: AddressSchema.optional()
});

// PayPal Payment Schema
const PayPalPaymentSchema = z.object({
  paymentMethod: z.literal('paypal'),
  paypalEmail: z.string().email({ error: 'Please enter a valid PayPal email address' }),
  payerId: z.string().optional(),
  returnUrl: z.string().url().optional(),
  cancelUrl: z.string().url().optional()
});

// Apple Pay Payment Schema
const ApplePayPaymentSchema = z.object({
  paymentMethod: z.literal('apple_pay'),
  applePayToken: z.string().min(1, { error: 'Apple Pay token is required' }),
  deviceId: z.string().min(1, { error: 'Device ID is required for Apple Pay' }),
  billingAddress: AddressSchema.optional()
});

// BNPL (Buy Now Pay Later) Payment Schema
const BNPLPaymentSchema = z.object({
  paymentMethod: z.literal('bnpl'),
  provider: BNPLProviderEnum,
  installmentPlan: z.enum(['pay_in_4', 'pay_in_6', 'pay_in_12']).optional(),
  termsAccepted: z.boolean().refine(val => val === true, {
    error: 'You must accept the BNPL terms and conditions'
  }),
  billingAddress: AddressSchema
});

// ============================================
// Discriminated Union for Payment Methods
// ============================================

const PaymentMethodDetailsSchema = z.discriminatedUnion('paymentMethod', [
  CreditCardPaymentSchema,
  BankTransferPaymentSchema,
  PayPalPaymentSchema,
  ApplePayPaymentSchema,
  BNPLPaymentSchema
]);

// ============================================
// Cross-Field Validation Constants
// ============================================

export const VALIDATION_RULES = {
  BNPL_MINIMUM_AMOUNT: 50,
  BANK_TRANSFER_VERIFICATION_THRESHOLD: 5000,
  SUPPORTED_CURRENCIES_FOR_BNPL: ['USD', 'EUR', 'GBP'] as const,
  MAX_BNPL_AMOUNT: 50000
} as const;

// ============================================
// Payment Schema V2 with Cross-Field Validation
// ============================================

export const PaymentSchemaV2 = BasePaymentFieldsSchema
  .and(PaymentMethodDetailsSchema)
  .superRefine((data, ctx) => {
    // ========================================
    // BNPL Cross-Field Validation
    // ========================================
    if (data.paymentMethod === 'bnpl') {
      // Minimum amount validation for BNPL ($50 minimum)
      if (data.amount < VALIDATION_RULES.BNPL_MINIMUM_AMOUNT) {
        ctx.addIssue({
          code: 'custom',
          message: `Buy Now Pay Later requires a minimum order amount of $${VALIDATION_RULES.BNPL_MINIMUM_AMOUNT}`,
          path: ['amount'],
          input: data.amount
        });
      }

      // Maximum amount validation for BNPL
      if (data.amount > VALIDATION_RULES.MAX_BNPL_AMOUNT) {
        ctx.addIssue({
          code: 'custom',
          message: `Buy Now Pay Later is not available for orders over $${VALIDATION_RULES.MAX_BNPL_AMOUNT.toLocaleString()}`,
          path: ['paymentMethod'],
          input: data.paymentMethod
        });
      }

      // Currency support validation for BNPL
      if (!VALIDATION_RULES.SUPPORTED_CURRENCIES_FOR_BNPL.includes(data.currency as 'USD' | 'EUR' | 'GBP')) {
        ctx.addIssue({
          code: 'custom',
          message: `Buy Now Pay Later is only available in ${VALIDATION_RULES.SUPPORTED_CURRENCIES_FOR_BNPL.join(', ')}`,
          path: ['currency'],
          input: data.currency
        });
      }
    }

    // ========================================
    // Bank Transfer Cross-Field Validation
    // ========================================
    if (data.paymentMethod === 'bank_transfer') {
      // Account verification required for amounts over $5000
      if (data.amount > VALIDATION_RULES.BANK_TRANSFER_VERIFICATION_THRESHOLD) {
        if (!data.isVerified) {
          ctx.addIssue({
            code: 'custom',
            message: `Account verification is required for transfers over $${VALIDATION_RULES.BANK_TRANSFER_VERIFICATION_THRESHOLD.toLocaleString()}. Please verify your bank account before proceeding.`,
            path: ['isVerified'],
            input: data.isVerified
          });
        }
      }
    }

    // ========================================
    // Credit Card Currency Validation
    // ========================================
    if (data.paymentMethod === 'credit_card') {
      // Additional card validation could go here
      // e.g., card type detection, Luhn algorithm validation
    }

    // ========================================
    // PayPal Validation
    // ========================================
    if (data.paymentMethod === 'paypal') {
      // PayPal-specific validations
    }

    // ========================================
    // Apple Pay Validation
    // ========================================
    if (data.paymentMethod === 'apple_pay') {
      // Apple Pay-specific validations
    }
  });

// ============================================
// Type Exports
// ============================================

export type PaymentV2 = z.infer<typeof PaymentSchemaV2>;

export type CreditCardPayment = z.infer<typeof CreditCardPaymentSchema>;
export type BankTransferPayment = z.infer<typeof BankTransferPaymentSchema>;
export type PayPalPayment = z.infer<typeof PayPalPaymentSchema>;
export type ApplePayPayment = z.infer<typeof ApplePayPaymentSchema>;
export type BNPLPayment = z.infer<typeof BNPLPaymentSchema>;

export type PaymentMethodDetails = z.infer<typeof PaymentMethodDetailsSchema>;
export type Address = z.infer<typeof AddressSchema>;

// ============================================
// Legacy Payment Schema - v1.0 (Backward Compatibility)
// ============================================

/**
 * @deprecated Use PaymentSchemaV2 instead. This schema is maintained for backward compatibility.
 * Only supports credit card payments.
 */
export const PaymentSchemaV1 = z.object({
  orderId: z.string().uuid(),
  amount: z.number().positive(),
  currency: z.enum(['USD', 'EUR', 'GBP']),
  paymentMethod: z.literal('credit_card'),
  cardNumber: z.string().length(16),
  cardExpiry: z.string().regex(/^\d{2}\/\d{2}$/),
  cardCvv: z.string().length(3),
  billingAddress: z.object({
    street: z.string(),
    city: z.string(),
    zipCode: z.string(),
    country: z.string()
  })
});

export type PaymentV1 = z.infer<typeof PaymentSchemaV1>;

// ============================================
// Backward Compatibility Layer
// ============================================

/**
 * Converts a v1 payment to v2 format
 */
export function migrateV1ToV2(v1Payment: PaymentV1): PaymentV2 {
  return {
    ...v1Payment,
    cardholderName: '', // Required in v2, default empty for migration
    paymentMethod: 'credit_card' as const
  } as PaymentV2;
}

/**
 * Validates a v1 payment and returns a v2 compatible result
 */
export function validateLegacyPayment(data: unknown): {
  success: boolean;
  data?: PaymentV2;
  error?: z.ZodError;
} {
  const v1Result = PaymentSchemaV1.safeParse(data);

  if (!v1Result.success) {
    return { success: false, error: v1Result.error };
  }

  // Convert to v2 format
  const v2Data = migrateV1ToV2(v1Result.data);

  // Validate with v2 schema
  const v2Result = PaymentSchemaV2.safeParse(v2Data);

  if (!v2Result.success) {
    return { success: false, error: v2Result.error };
  }

  return { success: true, data: v2Result.data };
}

/**
 * Schema adapter for gradual migration
 * Accepts both v1 and v2 payment formats
 */
export const PaymentSchemaBackwardCompatible = z.union([
  PaymentSchemaV2,
  PaymentSchemaV1.transform(migrateV1ToV2)
]);

// ============================================
// Utility Functions
// ============================================

/**
 * Type guard to check if payment is a credit card payment
 */
export function isCreditCardPayment(payment: PaymentV2): payment is PaymentV2 & CreditCardPayment {
  return payment.paymentMethod === 'credit_card';
}

/**
 * Type guard to check if payment is a bank transfer payment
 */
export function isBankTransferPayment(payment: PaymentV2): payment is PaymentV2 & BankTransferPayment {
  return payment.paymentMethod === 'bank_transfer';
}

/**
 * Type guard to check if payment is a PayPal payment
 */
export function isPayPalPayment(payment: PaymentV2): payment is PaymentV2 & PayPalPayment {
  return payment.paymentMethod === 'paypal';
}

/**
 * Type guard to check if payment is an Apple Pay payment
 */
export function isApplePayPayment(payment: PaymentV2): payment is PaymentV2 & ApplePayPayment {
  return payment.paymentMethod === 'apple_pay';
}

/**
 * Type guard to check if payment is a BNPL payment
 */
export function isBNPLPayment(payment: PaymentV2): payment is PaymentV2 & BNPLPayment {
  return payment.paymentMethod === 'bnpl';
}

/**
 * Get the payment method type from a payment object
 */
export function getPaymentMethodType(payment: PaymentV2): PaymentMethod {
  return payment.paymentMethod;
}

/**
 * Check if a payment method requires billing address
 */
export function requiresBillingAddress(paymentMethod: PaymentMethod): boolean {
  return ['credit_card', 'bnpl'].includes(paymentMethod);
}

/**
 * Get supported currencies for a payment method
 */
export function getSupportedCurrencies(paymentMethod: PaymentMethod): Currency[] {
  switch (paymentMethod) {
    case 'bnpl':
      return ['USD', 'EUR', 'GBP'];
    case 'credit_card':
    case 'bank_transfer':
    case 'paypal':
    case 'apple_pay':
      return ['USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD'];
    default:
      return ['USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD'];
  }
}

// ============================================
// Validation Helpers for Form Libraries
// ============================================

/**
 * Create a validation schema for a specific payment method
 */
export function getPaymentMethodSchema(method: PaymentMethod) {
  switch (method) {
    case 'credit_card':
      return CreditCardPaymentSchema;
    case 'bank_transfer':
      return BankTransferPaymentSchema;
    case 'paypal':
      return PayPalPaymentSchema;
    case 'apple_pay':
      return ApplePayPaymentSchema;
    case 'bnpl':
      return BNPLPaymentSchema;
    default:
      throw new Error(`Unknown payment method: ${method}`);
  }
}

/**
 * Partial schema for step-by-step form validation
 */
export const PaymentStep1Schema = BasePaymentFieldsSchema;
export const PaymentStep2Schema = PaymentMethodDetailsSchema;

export type PaymentStep1 = z.infer<typeof PaymentStep1Schema>;
export type PaymentStep2 = z.infer<typeof PaymentStep2Schema>;
"}

