## Migration Steps

### Step 1: Update Dependencies

Ensure you have the required packages:

```bash
npm install zod@^4.0.0
# For React Hook Form integration:
npm install react-hook-form @hookform/resolvers
```

### Step 2: Import New Schema

```typescript
// Before (V1)
import { PaymentSchema } from './schemas/paymentSchema';

// After (V2)
import {
  PaymentSchemaV2,
  PaymentSchemaV1,           // Keep for backward compatibility
  PaymentSchemaBackwardCompatible
} from './schemas/paymentSchema';
```

### Step 3: Update Payment Forms

#### Before (V1 - Credit Card Only):

```tsx
function PaymentForm() {
  return (
    <form>
      <input name="cardNumber" />
      <input name="cardExpiry" />
      <input name="cardCvv" />
      {/* ... */}
    </form>
  );
}
```

#### After (V2 - Multiple Payment Methods):

```tsx
function PaymentForm() {
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('credit_card');

  return (
    <form>
      <select value={paymentMethod} onChange={e => setPaymentMethod(e.target.value)}>
        <option value="credit_card">Credit Card</option>
        <option value="bank_transfer">Bank Transfer</option>
        <option value="paypal">PayPal</option>
        <option value="apple_pay">Apple Pay</option>
        <option value="bnpl">Buy Now Pay Later</option>
      </select>

      {/* Conditionally render fields based on payment method */}
      {paymentMethod === 'credit_card' && <CreditCardFields />}
      {paymentMethod === 'bank_transfer' && <BankTransferFields />}
      {paymentMethod === 'paypal' && <PayPalFields />}
      {paymentMethod === 'apple_pay' && <ApplePayFields />}
      {paymentMethod === 'bnpl' && <BNPLFields />}
    </form>
  );
}
```

### Step 4: Update API Calls

```typescript
// Before (V1)
async function processPayment(payment: PaymentV1) {
  return fetch('/api/payments', {
    method: 'POST',
    body: JSON.stringify(payment)
  });
}

// After (V2)
async function processPayment(payment: PaymentV2) {
  // Use type guards for payment-method-specific logic
  if (isBNPLPayment(payment)) {
    // Handle BNPL-specific processing
    console.log('BNPL provider:', payment.provider);
  }

  return fetch('/api/payments/v2', {
    method: 'POST',
    body: JSON.stringify(payment)
  });
}
```

### Step 5: Update Error Handling

```typescript
// V2 provides more detailed errors
function handlePaymentSubmit(data: unknown) {
  const result = PaymentSchemaV2.safeParse(data);

  if (!result.success) {
    // Errors are now field-specific with user-friendly messages
    result.error.issues.forEach(issue => {
      console.log(`Field: ${issue.path.join('.')}`);
      console.log(`Message: ${issue.message}`);
    });
    return;
  }

  // Process valid payment
  processPayment(result.data);
}
