## Code Examples

### React Hook Form Integration

```tsx
import { useForm } from 'react-hook-form';
import { PaymentSchemaV2, type PaymentV2 } from './schemas/paymentSchema';
import { zodResolver } from '@hookform/resolvers/zod';

function CheckoutForm() {
  const {
    register,
    handleSubmit,
    watch,
    formState: { errors, isSubmitting }
  } = useForm<PaymentV2>({
    resolver: zodResolver(PaymentSchemaV2),
    defaultValues: {
      currency: 'USD',
      paymentMethod: 'credit_card'
    }
  });

  const paymentMethod = watch('paymentMethod');
  const amount = watch('amount');

  const onSubmit = async (data: PaymentV2) => {
    try {
      await processPayment(data);
      // Handle success
    } catch (error) {
      // Handle error
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      {/* Payment Method Selector */}
      <select {...register('paymentMethod')}>
        <option value="credit_card">Credit Card</option>
        <option value="bank_transfer">Bank Transfer</option>
        <option value="paypal">PayPal</option>
        <option value="apple_pay">Apple Pay</option>
        <option value="bnpl">Buy Now Pay Later</option>
      </select>

      {/* Common Fields */}
      <input {...register('amount', { valueAsNumber: true })} type="number" />
      {errors.amount && <span>{errors.amount.message}</span>}

      {/* Conditional Fields */}
      {paymentMethod === 'credit_card' && (
        <>
          <input {...register('cardNumber')} placeholder="Card Number" />
          <input {...register('cardExpiry')} placeholder="MM/YY" />
          <input {...register('cardCvv')} placeholder="CVV" />
        </>
      )}

      {/* BNPL-specific warnings */}
      {paymentMethod === 'bnpl' && amount < 50 && (
        <div className="warning">
          Minimum order for BNPL is $50
        </div>
      )}

      <button type="submit" disabled={isSubmitting}>
        Pay Now
      </button>
    </form>
  );
}
```

### Using Type Guards

```typescript
import {
  isCreditCardPayment,
  isBankTransferPayment,
  isPayPalPayment,
  isApplePayPayment,
  isBNPLPayment,
  type PaymentV2
} from './schemas/paymentSchema';

function processPayment(payment: PaymentV2) {
  switch (payment.paymentMethod) {
    case 'credit_card':
      // TypeScript knows payment is CreditCardPayment
      console.log('Processing card:', payment.cardNumber.slice(-4));
      break;

    case 'bank_transfer':
      // TypeScript knows payment is BankTransferPayment
      console.log('Bank transfer to:', payment.bankName);
      if (!payment.isVerified && payment.amount > 5000) {
        throw new Error('Verification required');
      }
      break;

    case 'paypal':
      console.log('PayPal payment from:', payment.paypalEmail);
      break;

    case 'apple_pay':
      console.log('Apple Pay token:', payment.applePayToken);
      break;

    case 'bnpl':
      console.log('BNPL provider:', payment.provider);
      break;
  }
}
