## Error Handling

### Error Response Structure

```typescript
// Validation errors from Zod
interface ZodError {
  issues: Array<{
    code: string;
    message: string;      // User-friendly message
    path: string[];       // Field path, e.g., ['cardNumber'] or ['billingAddress', 'street']
    input?: unknown;      // The invalid input value
  }>;
}
```

### Formatting Errors for Display

```typescript
import { z } from 'zod';

function formatErrors(result: z.SafeParseError) {
  const errors: Record<string, string> = {};

  result.error.issues.forEach(issue => {
    const field = issue.path.join('.');
    errors[field] = issue.message;
  });

  return errors;
}

// Example output:
// {
//   'cardNumber': 'Please enter a valid 16-digit card number',
//   'amount': 'Buy Now Pay Later requires a minimum order amount of $50'
// }
```

